      out.write("					var expires = new Date();\r\n");
      out.write("					expires.setTime(expires.getTime() + (expiry * 24 * 60 * 60 * 1000));\r\n");
      out.write("					document.cookie = key + '=' + value + ';expires=' + expires.toUTCString() + ';path=/';\r\n");
      out.write("				}\r\n");
      out.write("\r\n");
      out.write("				function getCookie(key) {\r\n");
      out.write("					var name = key + \"=\";\r\n");
      out.write("					var decodedCookie = decodeURIComponent(document.cookie);\r\n");
      out.write("					var ca = decodedCookie.split(';');\r\n");
      out.write("					for (var i = 0; i < ca.length; i++) {\r\n");
      out.write("						var c = ca[i];\r\n");
      out.write("						while (c.charAt(0) == ' ') {\r\n");
      out.write("							c = c.substring(1);\r\n");
      out.write("						}\r\n");
      out.write("						if (c.indexOf(name) == 0) {\r\n");
      out.write("							return c.substring(name.length, c.length);\r\n");
      out.write("						}\r\n");
      out.write("					}\r\n");
      out.write("					return \"\";\r\n");
      out.write("				}\r\n");
      out.write("\r\n");
      out.write("				function googleTranslateElementInit() {\r\n");
      out.write("					new google.translate.TranslateElement({\r\n");
