      out.write("						layout: google.translate.TranslateElement.InlineLayout.SIMPLE,\r\n");
      out.write("						autoDisplay: true\r\n");
      out.write("					}, 'google_translate_element');\r\n");
      out.write("\r\n");
      out.write("					// Persistent Language Logic\r\n");
      out.write("					var preferredLang = localStorage.getItem('preferredLanguage') || getCookie('selectedLang');\r\n");
      out.write("					if (preferredLang && preferredLang !== 'en') {\r\n");
      out.write("						var checkExist = setInterval(function () {\r\n");
      out.write("							var select = document.querySelector('select.goog-te-combo');\r\n");
      out.write("							if (select) {\r\n");
      out.write("								if (select.value !== preferredLang) {\r\n");
      out.write("									translateLanguage(preferredLang);\r\n");
      out.write("								}\r\n");
      out.write("								clearInterval(checkExist);\r\n");
      out.write("							}\r\n");
      out.write("						}, 100);\r\n");
      out.write("						setTimeout(function () { clearInterval(checkExist); }, 8000);\r\n");
      out.write("					}\r\n");
      out.write("				}\r\n");
      out.write("\r\n");
      out.write("				function translateLanguage(langCode) {\r\n");
      out.write("					var select = document.querySelector('select.goog-te-combo');\r\n");
      out.write("\r\n");
      out.write("					// Update persistence\r\n");
      out.write("					localStorage.setItem('preferredLanguage', langCode);\r\n");
      out.write("					setCookie('selectedLang', langCode, 7);\r\n");
      out.write("					setCookie('googtrans', '/en/' + langCode, 7);\r\n");
      out.write("\r\n");
      out.write("					// Update UI Label\r\n");
      out.write("					var label = document.getElementById('currentLangLabel');\r\n");
      out.write("					if (label) {\r\n");
      out.write("						label.innerText = (langCode === 'kn') ? 'ಕನ್ನಡ' : 'English';\r\n");
      out.write("					}\r\n");
      out.write("\r\n");
      out.write("					if (select) {\r\n");
      out.write("						select.value = langCode;\r\n");
      out.write("						select.dispatchEvent(new Event('change'));\r\n");
      out.write("					} else {\r\n");
      out.write("						// Retry once if widget not loaded\r\n");
      out.write("						setTimeout(function () {\r\n");
      out.write("							var selectRetry = document.querySelector('select.goog-te-combo');\r\n");
      out.write("							if (selectRetry) {\r\n");
